/**
 * Mock data for Customers · Retention.
 *
 * Five instruments:
 *  1. Cohort retention triangle (rows = acquisition months, cols = M0..M8)
 *  2. Trend sparks for M1 / M3 / M6 retention over the cohorts
 *  3. Purchase-cycle distribution (days between orders)
 *  4. LTV & payback dual-line w/ CAC reference & cross-beacon
 *  5. Channels × retention table + coupon vs full-price cut
 *  6. Going-cold ranked list
 *
 * USD currency per canonical rule.
 */

export interface CohortRow {
  month: string;
  size: number;
  /** Retention % per month (M0 = 100, M1..). Younger cohorts have shorter arrays. */
  retention: number[];
}

