export type PaybackMode = "blended" | "email" | "meta";

export interface PaybackData {
  /** Customer Acquisition Cost in USD. */
  cac: number;
  /** Line color. */
  color: string;
  /** Cumulative revenue per customer at month 0..12. */
  cum: number[];
  /** Whether to render the LY ghost line. */
  ghost: boolean;
  ltv: string;
  ltvCls: "green" | "red";
  pay: string;
  delta: string;
  dCls: "up" | "down";
  pay2: string;
  /** Read-out paragraph (HTML — supports <b>). */
  read: string;
  readCls: "" | "ok" | "warn";
}

