"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { SparkLine } from "@/components/charts/SparkLine";
import { PaybackCurve } from "@/components/charts/PaybackCurve";
import { useBridge } from "@/features/bridge/hooks/use-bridge";
import {
  COHORTS,
  cohortColumn,
  PURCHASE_CYCLE,
  PAYBACK,
  PAYBACK_GHOST,
  CHANNELS,
  GOING_COLD,
  retentionMetrics,
  retentionAI,
  type PaybackMode,
} from "@/features/customers/api/customers-retention-data";
import "./retention.css";

const PERIOD_LABELS = ["Last 90 days", "Last 12 months", "All time"];

const SECTIONS = [
  { id: "s-cohort", label: "Cohorts" },
  { id: "s-cycles", label: "Purchase cycles" },
  { id: "s-payback", label: "LTV & payback" },
  { id: "s-channels", label: "Channels" },
  { id: "s-cold", label: "Going cold", count: GOING_COLD.length },
];

export default function RetentionPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [activeSection, setActiveSection] = useState("s-cohort");
  const [pbMode, setPbMode] = useState<PaybackMode>("blended");
  const [chanSortKey, setChanSortKey] =
    useState<"name" | "acquired" | "ret3" | "ltvNum">("ret3");
  const [chanSortDir, setChanSortDir] = useState<1 | -1>(-1);
  const { openBridge } = useBridge();

  const channels = useMemo(() => {
    const arr = [...CHANNELS];
    arr.sort((a, b) => {
      if (chanSortKey === "name") return chanSortDir * a.name.localeCompare(b.name);
      return chanSortDir * ((a[chanSortKey] as number) - (b[chanSortKey] as number));
    });
    return arr;
  }, [chanSortKey, chanSortDir]);

  const scrollTo = (id: string) => {
    setActiveSection(id);
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  };

  return (
    <div className="customers-retention-page">
      <DeptHeader
        dept="customers"
        title="Retention"
        meta={
          <>
            <span className="live">Live</span> · 2,140 customers · 9 cohorts · vs same period last year
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <button
              className="btn-util primary"
              type="button"
              onClick={() => openBridge("customers")}
            >
              Build win-back → Bridge
            </button>
          </>
        }
      />
      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Repeat rate</div>
          <div className="metric-v green">{retentionMetrics.repeat}{retentionMetrics.repeatSuffix}</div>
          <div className="metric-yoy up">{retentionMetrics.repeatDelta} <span className="yl">YoY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">New-cohort retention · M1</div>
          <div className="metric-v red">{retentionMetrics.newM1}{retentionMetrics.newM1Suffix}</div>
          <div className="metric-yoy down">{retentionMetrics.newM1Delta} <span className="yl">YoY</span></div>
        </div>
        <div className="metric">
          <div className="metric-l">LTV : CAC</div>
          <div className="metric-v green">{retentionMetrics.ltvCac}{retentionMetrics.ltvCacSuffix}</div>
          <div className="metric-yoy up">{retentionMetrics.ltvCacDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Payback</div>
          <div className="metric-v">
            {retentionMetrics.payback}
            <span style={{ fontSize: 15, color: "var(--ink-3)" }}> {retentionMetrics.paybackUnit}</span>
          </div>
          <div className="metric-yoy up">{retentionMetrics.paybackDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Going cold</div>
          <div className="metric-v red">{retentionMetrics.cold}</div>
          <div className="metric-yoy down">{retentionMetrics.coldDelta}</div>
        </div>
      </div>

      <AIStrip label={retentionAI.label} meta={retentionAI.meta} cards={retentionAI.cards} />

      <div className="secnav">
        {SECTIONS.map((s) => (
          <button
            key={s.id}
            type="button"
            className={activeSection === s.id ? "active" : ""}
            onClick={() => scrollTo(s.id)}
          >
            {s.label}
            {s.count !== undefined && <span className="ct">{s.count}</span>}
          </button>
        ))}
      </div>

      {/* 1 — Cohort retention */}
      <section className="section" id="s-cohort">
        <SectionLabel>
          <span className="n">1</span> Cohort retention <span className="sl-note">— do new customers come back, and is it getting better or worse?</span>
        </SectionLabel>
        <div className="icard">
          <div className="ic-head">
            <div className="ic-title">Retention by acquisition cohort</div>
            <div className="ic-sub">% of each month&rsquo;s new customers still ordering · M0 = acquisition month</div>
          </div>
          <CohortGrid />
          <TrendCards />
          <div className="guard">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <circle cx="12" cy="12" r="9" />
              <path d="M12 8v4M12 16h.01" />
            </svg>
            Compared at equal age only — younger cohorts aren&rsquo;t measured on months they haven&rsquo;t reached yet.
          </div>
          <div className="dc-read warn">
            Newer cohorts are retaining worse: month-1 retention has slipped from <b>49%</b> (September) to <b>39%</b> (April) — a 10-point decline in how well you keep first-time buyers. The loyal base still grows, so the headline looks fine, but the front door is leaking. Something shifted in acquisition or onboarding around Q1.
          </div>
        </div>
      </section>

      {/* 2 — Purchase cycles */}
      <section className="section" id="s-cycles">
        <SectionLabel>
          <span className="n">2</span> Purchase cycles <span className="sl-note">— when do they reorder, and where does &ldquo;at risk&rdquo; begin?</span>
        </SectionLabel>
        <div className="icard">
          <div className="ic-head">
            <div className="ic-title">Time between orders</div>
            <div className="ic-sub">Distribution of days from one order to the next · this is where the segment thresholds come from</div>
          </div>
          <PurchaseCycleChart />
          <div className="dc-read">
            The typical customer reorders every <b>34 days</b>. That rhythm is where the segment thresholds come from — past 51 days they&rsquo;re At Risk, past 68 they&rsquo;re Going Cold. Not arbitrary windows; your own measured cadence.
          </div>
        </div>
      </section>

      {/* 3 — LTV & payback */}
      <section className="section" id="s-payback">
        <SectionLabel>
          <span className="n">3</span> LTV &amp; payback <span className="sl-note">— does a customer ever pay back what they cost to acquire?</span>
        </SectionLabel>
        <div className="icard">
          <div className="pb-head">
            <div className="pb-hero">
              <div className="pb-stat">
                <div className="hl">LTV : CAC</div>
                <div className={`hv ${PAYBACK[pbMode].ltvCls}`}>{PAYBACK[pbMode].ltv}</div>
                <div className={`hd ${PAYBACK[pbMode].dCls}`}>{PAYBACK[pbMode].delta}</div>
              </div>
              <div className="pb-stat">
                <div className="hl">Payback</div>
                <div className="hv">{PAYBACK[pbMode].pay}</div>
                <div className="hd">{PAYBACK[pbMode].pay2}</div>
              </div>
            </div>
            <div className="pb-right">
              <div className="pb-toggle">
                {(["blended", "email", "meta"] as PaybackMode[]).map((m) => (
                  <button
                    key={m}
                    type="button"
                    className={pbMode === m ? "active" : ""}
                    onClick={() => setPbMode(m)}
                  >
                    {m === "blended" ? "Blended" : m === "email" ? "Email" : "Paid Meta"}
                  </button>
                ))}
              </div>
              <div
                className="pb-legend"
                style={{ visibility: PAYBACK[pbMode].ghost ? "visible" : "hidden" }}
              >
                <span><i style={{ background: PAYBACK[pbMode].color }} />This year</span>
                <span><i className="ghost" />Last year</span>
              </div>
            </div>
          </div>
          <PaybackCurve
            data={{
              cac: PAYBACK[pbMode].cac,
              color: PAYBACK[pbMode].color,
              cum: PAYBACK[pbMode].cum,
              ghost: PAYBACK[pbMode].ghost ? PAYBACK_GHOST : undefined,
              ltv: PAYBACK[pbMode].ltv,
              pay: PAYBACK[pbMode].pay,
            }}
            id={pbMode}
            animateKey={pbMode}
            label="LTV & payback"
          />
          <div
            className={`dc-read ${PAYBACK[pbMode].readCls}`}
            dangerouslySetInnerHTML={{ __html: PAYBACK[pbMode].read }}
          />
        </div>
      </section>

      {/* 4 — Channels */}
      <section className="section" id="s-channels">
        <SectionLabel>
          <span className="n">4</span> Acquisition × retention <span className="sl-note">— which sources actually build the base, and which just buy one-time orders?</span>
        </SectionLabel>
        <div className="row-card">
          <div className="cr-head">
            {(
              [
                ["name", "Channel"],
                ["acquired", "Acquired"],
                ["ret3", "3-mo ret."],
                [null, "Retention quality"],
                ["ltvNum", "LTV:CAC"],
                [null, "Verdict"],
              ] as Array<[("name" | "acquired" | "ret3" | "ltvNum") | null, string]>
            ).map(([k, label], i) => {
              const sortable = k !== null;
              const active = sortable && chanSortKey === k;
              return (
                <span
                  key={i}
                  className={`cr-h${i > 0 ? " num" : ""}${active ? " active" : ""}`}
                  onClick={() => {
                    if (!k) return;
                    if (chanSortKey === k) setChanSortDir((d) => (d === 1 ? -1 : 1));
                    else {
                      setChanSortKey(k);
                      setChanSortDir(k === "name" ? 1 : -1);
                    }
                  }}
                  style={!sortable ? { cursor: "default" } : undefined}
                >
                  {label}
                  {sortable && active && <i className="sar">{chanSortDir < 0 ? "↓" : "↑"}</i>}
                </span>
              );
            })}
          </div>
          {channels.map((c) => {
            const max = Math.max(...CHANNELS.map((x) => x.ret3));
            return (
              <div
                key={c.name}
                className="cr-row"
                style={{ ["--vs" as string]: c.stripe } as React.CSSProperties}
              >
                <span className="cr-name">{c.name}</span>
                <span className="cr-num">{c.acquired}</span>
                <span className={`cr-num ${c.retCls}`}>{c.ret3}%</span>
                <div className="cr-bar">
                  <i
                    style={{
                      ["--w" as string]: `${Math.round((c.ret3 / max) * 100)}%`,
                      background: `linear-gradient(180deg,${c.bar[0]},${c.bar[1]})`,
                    } as React.CSSProperties}
                  />
                </div>
                <span className={`cr-num ${c.ltvCls}`}>{c.ltv}</span>
                <span className={`vpill ${c.verdict}`}>{c.verdictLabel}</span>
              </div>
            );
          })}
        </div>
        <div className="dc-read warn">
          Email and Organic customers retain more than <b>2×</b> better than Paid Meta — and cost a fraction to acquire. You&rsquo;re spending the most to buy the customers who leave fastest. Shift Meta budget toward the channels that retain.
        </div>

        <div className="cut">
          <div className="cut-card" style={{ ["--cc" as string]: "var(--loss)" } as React.CSSProperties}>
            <div className="cl">Coupon-acquired · 392 customers</div>
            <div className="cut-row">
              <div className="cut-m"><div className="ml">Repeat rate</div><div className="mv red">18%</div></div>
              <div className="cut-m"><div className="ml">Avg LTV</div><div className="mv">$1,200</div></div>
              <div className="cut-m"><div className="ml">LTV:CAC</div><div className="mv red">1.4×</div></div>
            </div>
          </div>
          <div className="cut-card" style={{ ["--cc" as string]: "var(--d-finance)" } as React.CSSProperties}>
            <div className="cl">Full-price acquired · 1,748 customers</div>
            <div className="cut-row">
              <div className="cut-m"><div className="ml">Repeat rate</div><div className="mv green">44%</div></div>
              <div className="cut-m"><div className="ml">Avg LTV</div><div className="mv">$3,100</div></div>
              <div className="cut-m"><div className="ml">LTV:CAC</div><div className="mv green">4.2×</div></div>
            </div>
          </div>
        </div>
        <div className="dc-read warn">
          A first-order discount buys a customer who doesn&rsquo;t come back: coupon-acquired customers repeat at <b>18%</b> versus 44% at full price, returning under a third of the lifetime value. You paid them to leave.
        </div>
      </section>

      {/* 5 — Going cold */}
      <section className="section" id="s-cold">
        <SectionLabel>
          <span className="n">5</span> Going cold <span className="sl-note">— who&rsquo;s slipping away, and what&rsquo;s worth recovering?</span>
        </SectionLabel>
        <div className="gc-intro">
          <b>{GOING_COLD.length} going cold</b> · $185K exposed · <b>$95K recoverable</b> — ranked by win-back value, not by who&rsquo;s loudest
        </div>
        <div className="row-card">
          {GOING_COLD.map((g, i) => {
            const max = Math.max(...GOING_COLD.map((x) => x.recoverable));
            return (
              <div key={g.name} className="gc-row">
                <span className="gc-rank">{i + 1}</span>
                <div>
                  <div className="gc-name">{g.name}</div>
                  <div className="gc-sub">{g.sub}</div>
                </div>
                <div className="gc-bar">
                  <i style={{ ["--w" as string]: `${Math.max(4, (g.recoverable / max) * 100)}%` } as React.CSSProperties} />
                </div>
                <div className="gc-money">
                  <div className="m">${g.recoverable.toLocaleString()}</div>
                  <div className="u">recoverable</div>
                </div>
                <span className="vpill recover">Recover</span>
              </div>
            );
          })}
        </div>
        <div className="dc-read ok">
          The top 20 names hold roughly 60% of the recoverable value. A targeted sequence to those — not a blast to all 98 — is how win-back stays profitable. Send the ranked list to the Bridge to build the flow.
        </div>
      </section>

      <div className="foot-note">
        <span className="mk" />
        <p>
          Retention is where a customer business is won or lost: you&rsquo;re either buying one-time orders, or building customers who pay back what they cost and then some. This room answers <b>do they come back</b>, <b>does it pay off</b>, <b>which acquisition builds the base</b>, and <b>are we getting better or worse</b>.
        </p>
      </div>
    </div>
  );
}

/* ─── Cohort triangle ─── */
function CohortGrid() {
  return (
    <div className="ch-scroll">
      <div className="ch-grid">
        <div className="ch-corner">Cohort</div>
        {Array.from({ length: 9 }, (_, m) => (
          <div key={`h-${m}`} className="ch-cell ch-h">M{m}</div>
        ))}
        {COHORTS.map((c) => (
          <CohortRowEl key={c.month} c={c} />
        ))}
      </div>
    </div>
  );
}
function CohortRowEl({ c }: { c: (typeof COHORTS)[number] }) {
  return (
    <>
      <div className="ch-rowlabel">
        <b>{c.month}</b>
        <span>{c.size}</span>
      </div>
      {Array.from({ length: 9 }, (_, m) => {
        if (m >= c.retention.length) return <div key={m} className="ch-cell ch-empty" />;
        const r = c.retention[m];
        const a = (r / 100) * 0.8 + 0.05;
        const tc = a > 0.42 ? "#fff" : "#7a3a55";
        return (
          <div
            key={m}
            className="ch-cell ch-v"
            style={{ background: `rgba(212,83,126,${a.toFixed(2)})`, color: tc }}
          >
            {r}
            <span>%</span>
          </div>
        );
      })}
    </>
  );
}

/* ─── Trend sparks ─── */
function TrendCards() {
  const defs = [
    { lab: "Month 1 retention", m: 1 },
    { lab: "Month 3 retention", m: 3 },
    { lab: "Month 6 retention", m: 6 },
  ];
  return (
    <div className="trend-wrap">
      {defs.map((d) => {
        const v = cohortColumn(d.m);
        const first = v[0];
        const last = v[v.length - 1];
        const dl = last - first;
        const dir = dl < -1 ? "dn" : dl > 1 ? "up" : "flat";
        const arrow = dl < -1 ? "↓" : dl > 1 ? "↑" : "→";
        const tc = dl < -1 ? "var(--loss)" : dl > 1 ? "var(--d-finance)" : "var(--ink-3)";
        const lastMonth = COHORTS.filter((c) => c.retention.length > d.m).slice(-1)[0]?.month;
        return (
          <div key={d.m} className="trend-card" style={{ ["--tc" as string]: tc } as React.CSSProperties}>
            <div className="trend-top">
              <span className="trend-lab">{d.lab}</span>
              <span className={`trend-dir ${dir}`}>
                {arrow} {dl > 0 ? "+" : ""}{dl}pp
              </span>
            </div>
            <div className="trend-spark">
              <SparkLine
                values={v}
                color={dir === "dn" ? "#d64545" : dir === "up" ? "#1D9E75" : "#8a8d94"}
                endDot
                height={42}
                strokeWidth={2}
                padY={5}
                label={`${d.lab} trend`}
              />
            </div>
            <div className="trend-foot">
              Sep <b>{first}%</b> → {lastMonth} <b>{last}%</b> · {v.length} cohorts
            </div>
          </div>
        );
      })}
    </div>
  );
}

/* ─── Purchase cycle bars ─── */
function PurchaseCycleChart() {
  const max = Math.max(...PURCHASE_CYCLE.map((b) => b.pct));
  return (
    <>
      <div className="cyc">
        {PURCHASE_CYCLE.map((b) => (
          <div key={b.range} className="cyc-col">
            <div className="cyc-n">{b.pct}%</div>
            <div
              className={`cyc-bar ${b.tone}`}
              style={{ ["--h" as string]: `${(b.pct / max) * 100}%` } as React.CSSProperties}
            />
          </div>
        ))}
      </div>
      <div className="cyc-x">
        {PURCHASE_CYCLE.map((b) => (
          <div key={b.range} className="cyc-xl">{b.range}</div>
        ))}
      </div>
      <div className="cyc-key">
        <div className="cyc-ki"><i style={{ background: "#1D9E75" }} /><span className="kl">Median <b>34 days</b> · healthy</span></div>
        <div className="cyc-ki"><i style={{ background: "#b88a2a" }} /><span className="kl">At Risk <b>51 days</b> · 1.5× cycle</span></div>
        <div className="cyc-ki"><i style={{ background: "#d64545" }} /><span className="kl">Going Cold <b>68 days</b> · 2× cycle</span></div>
      </div>
    </>
  );
}
