"use client";

/**
 * <PaybackCurve> — Tier-1 signature instrument for LTV vs CAC payback.
 *
 * Conforms to CHART-STANDARD §2:
 *   - viewBox === real pixel width via useChartSize (rule 2)
 *   - <ChartStates> wraps the SVG (rule 5)
 *   - Reduced-motion respected via usePrefersReducedMotion (rule 4)
 *   - No `preserveAspectRatio="none"`; no fixed-width viewBox
 *   - Props-driven; sample data exported below (rule 4 — §4 data contract)
 *
 * Visual signature: pre/post-payback zones (red/green washes), gridlines + y
 * labels inside the plot, gold corner brackets, area fill under the line, an
 * optional dashed ghost (LY) trail, a CAC reference with chip label, animated
 * stroke-dash draw-in line, square nodes, and a crossover beacon with a
 * cream-paper reading window. When the line never crosses CAC, a "no payback"
 * callout renders instead.
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface PaybackCurveData {
  /** Customer Acquisition Cost in USD. */
  cac: number;
  /** Line color (signature accent for this curve). */
  color: string;
  /** Cumulative revenue per customer at M0..M12 (13 points). */
  cum: number[];
  /** Optional 13-point last-year ghost trail. */
  ghost?: number[];
  /** Hero LTV multiplier, e.g. "3.4×". */
  ltv: string;
  /** Payback label e.g. "Day 74" or "Never". */
  pay: string;
}

export interface PaybackCurveProps {
  data: PaybackCurveData;
  state?: ChartState;
  height?: number;
  /** Used in empty/error copy and aria. */
  label?: string;
  /** Unique id suffix so multiple instances on a page don't share <defs>. */
  id?: string;
  /** Animation key — bump to retrigger draw-in (e.g. mode change). */
  animateKey?: string | number;
}

export const samplePaybackCurveData: PaybackCurveData = {
  cac: 420,
  color: "#D4537E",
  cum: [170, 280, 380, 470, 600, 720, 830, 940, 1040, 1130, 1230, 1330, 1420],
  ghost: [130, 230, 320, 400, 490, 580, 660, 740, 820, 900, 980, 1100, 1220],
  ltv: "3.4×",
  pay: "Day 74",
};

export function PaybackCurve({
  data,
  state = "ready",
  height = 384,
  label = "LTV & payback",
  id = "default",
  animateKey,
}: PaybackCurveProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 920 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    setDrawn(false);
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [animateKey, reduce]);

  const W = Math.max(640, width);
  const H = height;
  const padL = 14;
  const padR = 22;
  const padT = 30;
  const padB = 36;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  const allV = data.ghost ? [...data.cum, ...data.ghost, data.cac] : [...data.cum, data.cac];
  const yMax = Math.ceil((Math.max(...allV) * 1.14) / 100) * 100;
  const X = (i: number) => padL + (i / 12) * plotW;
  const Y = (v: number) => padT + (1 - v / yMax) * plotH;
  const pts = data.cum.map((v, i) => [X(i), Y(v)] as [number, number]);

  let crossM: number | null = null;
  if (data.cum[0] >= data.cac) crossM = 0;
  else {
    for (let i = 0; i < 12; i++) {
      if (data.cum[i] < data.cac && data.cum[i + 1] >= data.cac) {
        crossM = i + (data.cac - data.cum[i]) / (data.cum[i + 1] - data.cum[i]);
        break;
      }
    }
  }
  const ycac = Y(data.cac);
  const xc = crossM != null ? X(crossM) : null;

  const ghostPts = data.ghost?.map((v, i) => [X(i), Y(v)] as [number, number]) ?? [];
  const lineP = "M " + pts.map((p) => `${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" L ");
  const areaP =
    lineP +
    ` L ${pts[12][0].toFixed(1)} ${base.toFixed(1)} L ${pts[0][0].toFixed(1)} ${base.toFixed(1)} Z`;
  const ghostP = ghostPts.length
    ? "M " + ghostPts.map((p) => `${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" L ")
    : "";
  const lineLen = plotW + 80;
  const gradId = `pbg-${id}`;

  return (
    <div ref={ref}>
      <ChartStates state={state} height={H} label={label}>
        <svg
          className="pb-chart"
          viewBox={`0 0 ${W} ${H}`}
          style={{ display: "block", overflow: "visible" }}
        >
          <defs>
            <linearGradient id={gradId} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0" stopColor={data.color} stopOpacity="0.18" />
              <stop offset="1" stopColor={data.color} stopOpacity="0" />
            </linearGradient>
          </defs>

          {/* Pre-payback / post-payback zones */}
          {crossM != null ? (
            <>
              <rect x={padL} y={padT} width={(xc as number) - padL} height={plotH} fill="rgba(214,69,69,0.045)" />
              <rect x={xc as number} y={padT} width={W - padR - (xc as number)} height={plotH} fill="rgba(29,158,117,0.06)" />
            </>
          ) : (
            <rect x={padL} y={padT} width={plotW} height={plotH} fill="rgba(214,69,69,0.05)" />
          )}

          {/* Grid + y labels inside plot */}
          {[0, 1, 2, 3, 4].map((s) => {
            const v = (yMax * s) / 4;
            const yy = Y(v);
            return (
              <g key={s}>
                <line className="grid" x1={padL} y1={yy} x2={W - padR} y2={yy} />
                <text className="ylab" x={padL + 3} y={yy - 5}>
                  ${Math.round(v).toLocaleString()}
                </text>
              </g>
            );
          })}

          {/* X labels */}
          {[0, 2, 4, 6, 8, 10, 12].map((i) => (
            <text key={i} className="xlab" x={X(i)} y={base + 22}>
              M{i}
            </text>
          ))}

          {/* Area fill */}
          <path
            d={areaP}
            fill={`url(#${gradId})`}
            style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.8s 0.5s" }}
          />

          {/* Optional LY ghost line */}
          {ghostP && (
            <path
              d={ghostP}
              fill="none"
              stroke="#8a8d94"
              strokeWidth={1.6}
              strokeDasharray="4 4"
              style={{ opacity: drawn ? 0.85 : 0, transition: "opacity 0.8s 1.1s" }}
            />
          )}

          {/* CAC reference line + chip */}
          <line
            x1={padL}
            y1={ycac}
            x2={W - padR}
            y2={ycac}
            stroke="#3d4047"
            strokeWidth={1.4}
            strokeDasharray="5 4"
          />
          <rect x={W - padR - 94} y={ycac - 11} width={90} height={20} rx={4} fill="#3d4047" />
          <text
            x={W - padR - 49}
            y={ycac + 3}
            fontSize={10}
            fill="#fff"
            textAnchor="middle"
            fontFamily="JetBrains Mono, monospace"
            fontWeight={600}
            letterSpacing="0.04em"
          >
            CAC ${data.cac}
          </text>

          {/* Main line with stroke-dash draw-in */}
          <path
            d={lineP}
            fill="none"
            stroke={data.color}
            strokeWidth={2.6}
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.5s cubic-bezier(.3,.7,.3,1)",
            }}
          />

          {/* Square nodes */}
          {pts.map((p, i) => {
            const last = i === 12;
            return (
              <rect
                key={i}
                x={(p[0] - 2.8).toFixed(1)}
                y={(p[1] - 2.8).toFixed(1)}
                width={5.6}
                height={5.6}
                rx={1.2}
                fill={last ? data.color : "#fff"}
                stroke={data.color}
                strokeWidth={1.5}
                style={{
                  opacity: drawn ? 1 : 0,
                  transition: `opacity 0.4s ${0.3 + i * 0.055}s`,
                }}
              />
            );
          })}

          {/* End-of-line label */}
          <text
            x={(pts[12][0] - 6).toFixed(1)}
            y={(pts[12][1] - 11).toFixed(1)}
            fontSize={12.5}
            fill={data.color}
            textAnchor="end"
            fontWeight={600}
            fontFamily="Inter, sans-serif"
            style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.4s 1.4s" }}
          >
            ${data.cum[12].toLocaleString()} · {data.ltv}
          </text>

          {/* Crossover beacon + reading window OR no-payback callout */}
          {crossM != null ? (
            <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.4s 1.6s" }}>
              <line x1={xc as number} y1={ycac} x2={xc as number} y2={base} stroke="#5B7CB0" strokeWidth={1} strokeDasharray="3 3" opacity={0.55} />
              <circle cx={xc as number} cy={ycac} r={5} fill="#5B7CB0" />
              {!reduce && (
                <circle cx={xc as number} cy={ycac} r={5} fill="none" stroke="#5B7CB0" opacity={0.5}>
                  <animate attributeName="r" values="5;20" dur="2.2s" repeatCount="indefinite" />
                  <animate attributeName="opacity" values="0.5;0" dur="2.2s" repeatCount="indefinite" />
                </circle>
              )}
              {(() => {
                const rw = 128;
                const rx = Math.min(Math.max((xc as number) - rw / 2, padL), W - padR - rw);
                const ry = ycac - 58;
                return (
                  <>
                    <rect x={rx} y={ry} width={rw} height={40} rx={6} fill="#fffdf8" stroke="rgba(184,138,42,0.8)" strokeWidth={0.8} />
                    <rect x={rx} y={ry} width={3} height={40} rx={1.5} fill="#5B7CB0" />
                    <text x={rx + 14} y={ry + 16} fontSize={8.5} fill="#8a8d94" fontFamily="JetBrains Mono, monospace" letterSpacing="0.1em">
                      PAYBACK
                    </text>
                    <text x={rx + 14} y={ry + 32} fontSize={15} fill="#15171c" fontFamily="Inter, sans-serif" fontWeight={600}>
                      {data.pay}
                    </text>
                  </>
                );
              })()}
            </g>
          ) : (
            <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.4s 1.6s" }}>
              {(() => {
                const rw = 158;
                const rx = W - padR - rw;
                const ry = Y(data.cum[12]) - 52;
                return (
                  <>
                    <rect x={rx} y={ry} width={rw} height={40} rx={6} fill="#fffdf8" stroke="rgba(214,69,69,0.7)" strokeWidth={0.8} />
                    <rect x={rx} y={ry} width={3} height={40} rx={1.5} fill="#d64545" />
                    <text x={rx + 14} y={ry + 16} fontSize={8.5} fill="#b3322e" fontFamily="JetBrains Mono, monospace" letterSpacing="0.1em">
                      NO PAYBACK IN 12 MO
                    </text>
                    <text x={rx + 14} y={ry + 32} fontSize={15} fill="#15171c" fontFamily="Inter, sans-serif" fontWeight={600}>
                      {data.ltv} at month 12
                    </text>
                  </>
                );
              })()}
            </g>
          )}
        </svg>
      </ChartStates>
    </div>
  );
}
